import json
import re

def to_latin_id(level, de_word):
    s = de_word.lower()
    s = s.replace("ä", "ae").replace("ö", "oe").replace("ü", "ue").replace("ß", "ss")
    s = re.sub(r'[^a-z0-9\-]', '', s)
    return f"{level.lower()}-{s}"

