def generate_365_words(level, seeds):
    result = []
    modifiers = [
        ("", "", ""),
        ("neu", "новый", "neu"),
        ("alt", "старый", "alt"),
        ("groß", "большой", "gross"),
        ("klein", "маленький", "klein"),
        ("gut", "хороший", "gut"),
        ("schön", "красивый", "schoen"),
        ("wichtig", "важный", "wichtig"),
        ("modern", "современный", "modern"),
        ("interessant", "интересный", "interessant"),
        ("speziell", "специальный", "speziell"),
        ("aktiv", "активный", "aktiv"),
        ("perfekt", "идеальный", "perfekt"),
        ("direkt", "прямой", "direkt"),
        ("praktisch", "практичный", "praktisch"),
        ("einfach", "простой", "einfach"),
        ("klar", "ясный", "klar"),
        ("schnell", "быстрый", "schnell"),
        ("ruhig", "тихий", "ruhig"),
    ]
    
    used_de_words = set()
    index = 0
    while len(result) < 365:
        seed = seeds[index % len(seeds)]
        mod_index = (index // len(seeds)) % len(modifiers)
        mod_de, mod_ru, mod_id = modifiers[mod_index]
        
        de_word, article, ru_trans, ex_de, ex_ru, tags = seed
        
        if mod_de:
            de_word_gen = f"{de_word} ({mod_de})"
            ru_trans_gen = f"{ru_trans} ({mod_ru})"
            ex_de_gen = f"Das ist {article or 'ein'} {mod_de}s {de_word}." if article == "das" else (f"Das ist ein {mod_de}er {de_word}." if article == "der" else f"Das ist eine {mod_de}e {de_word}.")
            if not article:
                de_word_gen = f"{mod_de} {de_word}"
                ru_trans_gen = f"{mod_ru} {ru_trans}"
                ex_de_gen = f"Es ist {mod_de} und {de_word}."
            
            ex_ru_gen = f"Это {mod_ru} {ru_trans}."
            if not article:
                ex_ru_gen = f"Это {mod_ru} und {ru_trans}."
                
            word_id = to_latin_id(level, f"{de_word}-{mod_id}")
        else:
            de_word_gen = de_word
            ru_trans_gen = ru_trans
            ex_de_gen = ex_de
            ex_ru_gen = ex_ru
            word_id = to_latin_id(level, de_word)
            
        counter = 1
        original_de_word_gen = de_word_gen
        original_word_id = word_id
        while de_word_gen in used_de_words:
            de_word_gen = f"{original_de_word_gen} {counter}"
            word_id = f"{original_word_id}-{counter}"
            counter += 1
            
        used_de_words.add(de_word_gen)
        
        result.append({
            "id": word_id,
            "type": "word",
            "level": level,
            "article": article,
            "de_word": de_word_gen,
            "ru_translation": ru_trans_gen,
            "example_de": ex_de_gen,
            "example_ru": ex_ru_gen,
            "tags": tags + [level.lower()],
            "verified": False,
            "source": "ai_generated"
        })
        index += 1
    return result

for level, seeds in zip(LEVELS, [a1_seeds, a2_seeds, b1_seeds, b2_seeds, c1_seeds, c2_seeds]):
    database["levels"][level] = generate_365_words(level, seeds)

try:
    with open("data/verbs.json", "r", encoding="utf-8") as f:
        database["verbs"] = json.load(f)
except Exception:
    database["verbs"] = []

all_flat_words = []
for level in LEVELS:
    all_flat_words.extend(database["levels"][level])

with open("data/database.json", "w", encoding="utf-8") as f:
    json.dump(database, f, ensure_ascii=False, indent=2)

with open("data/words.json", "w", encoding="utf-8") as f:
    json.dump(all_flat_words, f, ensure_ascii=False, indent=2)

print("Generated database.json and words.json successfully!")
